This is good for the average and weighted average case, specifically for a small number of metrics, though I'm wondering how to extend this so the user can easily grab the aggregated (mean, max, min, std, ...) of all their metrics in a few lines of code. 

I roughly put together some pseudo-code for this:

```python
VALID_AGGREGATE_TYPE = Union[int,
        float,
        np.float32,
        np.float64,
        np.int32,
        np.int64
]

#########################################################
# Aggregation Functions
#########################################################

class AggregateFn():
    def aggregate():
        raise NotImplementedError

class Average(AggregateFn):
    def aggregate(values: List[VALID_AGGREGATE_TYPE]):
        return sum(values)/len(values)

class Max(AggregateFn):
    def aggregate(values: List[VALID_AGGREGATE_TYPE]):
        return max(values)

class WeightedAverage(AggregateFn):
    #TODO: figure out how to store weights
    def aggregate(values: List[VALID_AGGREGATE_TYPE]):
        #TODO: compute weighted average

#########################################################
# Results Preprocessors
#########################################################

AggregateResultsPreprocessor(ResultsPreprocessor):
    def __init__(aggregation_fn: AggregateFn, keys: Optional[List[str] = None):
        self.keys = keys
        self.aggregation_fn = aggregation_fn

    def preprocess(self, results: List[Dict]) -> List[Dict]:
        if self.keys is None:
             # TODO: find all keys of type VALID_AGGREGATE_TYPE
        for key in self.keys:
             values = [result[key] for result in results]
             aggregated_results = self.aggregation_fn(values)
             # TODO: do something with the result

AverageResultsPreprocessor(AggregateResultsPreprocessor):
    def __init__(keys: Optional[List[str]):
        super.__init(Average(), keys)

MaxResultsPreprocessor(AggregateResultsPreprocessor):
    def __init__(keys: Optional[List[str]):
        super.__init(Max(), keys)

WeightedAverageResultsPreprocessor(AggregateResultsPreprocessor):
    def __init__(keys: Optional[List[str],  str: weight_key):
        super.__init(keys, WeightedAverage(weight_key))
```

The user can then define their aggregation logic with:

```python
average_all_preprocessor = AverageResultsPreprocessor()
max_time_preprocessor = MaxResultsPreprocessor(["time"])
weighted_average_loss_preprocessor = WeightedAverageResultsPreprocessor(["loss"], "batch_size")

results_preprocessors=[average_all_preprocessor, max_time_preprocessor, weighted_average_loss_preprocessor]
            
trainer.run(train_func, results_preprocessors=results_preprocessors)
```


